create extension if not exists pgcrypto;
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade,email text,full_name text,current_role text,target_role text,location text,readiness integer default 0 check(readiness between 0 and 100),profile_data jsonb not null default '{}'::jsonb,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.career_goals (id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,title text not null,status text not null default 'active',target_date date,preferences jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create table public.career_tasks (id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,goal_id uuid references public.career_goals(id) on delete cascade,title text not null,description text,status text not null default 'todo',due_at timestamptz,readiness_impact integer default 0,evidence_id uuid,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.evidence (id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,title text not null,evidence_type text not null,description text,source_url text,storage_path text,skills text[] not null default '{}',verification_status text not null default 'claimed',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.job_analyses (id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,job_title text,job_description text not null,score integer check(score between 0 and 100),result jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create table public.agent_runs (id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,agent_type text not null check(agent_type in ('counselor','career','skills','evidence','jobs','learning','market','mentor','privacy','integrity','explainability','fairness','understand','explore','navigate','build','copilot360','linkedin')),input text not null,context jsonb not null default '{}'::jsonb,answer text,status text not null default 'running',summary text,model text,created_at timestamptz not null default now(),completed_at timestamptz);
create index on public.career_tasks(user_id,status);create index on public.evidence(user_id);create index on public.agent_runs(user_id,created_at desc);create index on public.job_analyses(user_id,created_at desc);
alter table public.profiles enable row level security;alter table public.career_goals enable row level security;alter table public.career_tasks enable row level security;alter table public.evidence enable row level security;alter table public.job_analyses enable row level security;alter table public.agent_runs enable row level security;
create policy "own profile" on public.profiles for all using(auth.uid()=id) with check(auth.uid()=id);
create policy "own goals" on public.career_goals for all using(auth.uid()=user_id) with check(auth.uid()=user_id);
create policy "own tasks" on public.career_tasks for all using(auth.uid()=user_id) with check(auth.uid()=user_id);
create policy "own evidence" on public.evidence for all using(auth.uid()=user_id) with check(auth.uid()=user_id);
create policy "own job analyses" on public.job_analyses for all using(auth.uid()=user_id) with check(auth.uid()=user_id);
create policy "own agent runs" on public.agent_runs for select using(auth.uid()=user_id);
create policy "insert own agent runs" on public.agent_runs for insert with check(auth.uid()=user_id);
create policy "update own agent runs" on public.agent_runs for update using(auth.uid()=user_id) with check(auth.uid()=user_id);
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.profiles(id,email,full_name) values(new.id,new.email,coalesce(new.raw_user_meta_data->>'full_name','')); return new; end; $$;
create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
insert into storage.buckets(id,name,public,file_size_limit,allowed_mime_types) values('career-evidence','career-evidence',false,10485760,array['application/pdf','image/png','image/jpeg','application/vnd.openxmlformats-officedocument.wordprocessingml.document']) on conflict(id) do nothing;
create policy "own evidence objects" on storage.objects for all using(bucket_id='career-evidence' and auth.uid()::text=(storage.foldername(name))[1]) with check(bucket_id='career-evidence' and auth.uid()::text=(storage.foldername(name))[1]);
